UPDATE engineering_articles SET body_html = REPLACE(body_html,
  '<h2>4. Размерные цепи: теория и терминология</h2><p>Размерная цепь — замкнутый контур взаимосвязанных размеров одной детали или сборочной единицы. Каждый размер цепи называется <strong>звеном</strong>.',
  '<h2>4. Размерные цепи: теория и терминология</h2><p>Терминология размерных цепей в РФ закреплена в <strong>ГОСТ 16319-80</strong> «Цепи размерные. Основные термины, обозначения и определения» [9], а методы расчёта — в <strong>ГОСТ 16320-80</strong> [10]. Теоретическую основу заложил А. Н. Колчин в труде «Основы технологии машиностроения: расчёт точности механической обработки» [1] — это первоисточник советской школы расчёта точности, к которому обращаются и поныне. Вузовская подача та же теория развёрнута у А. И. Якушева [3] и в курсе технологии машиностроения под ред. А. М. Дальского [2]. Прикладной справочный материал — у М. А. Палея [4] и в учебном пособии П. Ф. Дунаева/О. П. Леликова специально по расчёту допусков [5]. Размерная цепь — замкнутый контур взаимосвязанных размеров одной детали или сборочной единицы. Каждый размер цепи называется <strong>звеном</strong>.'
)
WHERE slug = 'razmernye-tsepi-dopuski-i-posadki-v-konstruktorskih-diplomah';